  1→import React, { useState, useMemo, useCallback, useEffect, lazy, Suspense } from 'react';
  2→import { User, AnalysisResult, SMCContent, GeneratedSolution } from './types';
  3→import { analyzeUrl } from './services/analyzer';
  4→import { db } from './services/database';
  5→import Home from './pages/Home';
  6→import Login from './pages/Login';
  7→import Analyze from './pages/Analyze';
  8→
  9→// Lazy-loaded pages for bundle optimization
 10→const Dashboard = lazy(() => import('./pages/Dashboard'));
 11→const GenerativeTools = lazy(() => import('./pages/GenerativeTools'));
 12→const Results = lazy(() => import('./pages/Results').then(m => ({ default: m.Results })));
 13→const HistoryView = lazy(() => import('./pages/History'));
 14→const SMCStudio = lazy(() => import('./pages/SMCStudio'));
 15→const SourceOfTruth = lazy(() => import('./pages/SourceOfTruth'));
 16→const SchemaOrg = lazy(() => import('./pages/SchemaOrg'));
 17→const PublisherRequest = lazy(() => import('./pages/PublisherRequest'));
 18→const RobotsTxt = lazy(() => import('./pages/RobotsTxt'));
 19→const Directory = lazy(() => import('./pages/Directory'));
 20→const DirectoryEntity = lazy(() => import('./pages/DirectoryEntity'));
 21→const Recharge = lazy(() => import('./pages/Recharge'));
 22→const Projects = lazy(() => import('./pages/Projects'));
 23→const Account = lazy(() => import('./pages/Account'));
 24→const Clients = lazy(() => import('./pages/Clients'));
 25→const Affiliation = lazy(() => import('./pages/Affiliation'));
 26→const ContentWriter = lazy(() => import('./pages/ContentWriter'));
 27→const Reputation = lazy(() => import('./pages/Reputation'));
 28→const BotTracking = lazy(() => import('./pages/BotTracking'));
 29→const Messages = lazy(() => import('./pages/Messages'));
 30→const AlertsAEO = lazy(() => import('./pages/AlertsAEO'));
 31→const MissionOrders = lazy(() => import('./pages/MissionOrders'));
 32→import {
 33→  LogOut, Zap, Github, Twitter, Linkedin, Home as HomeIcon, LayoutDashboard,
 34→  Globe, ScanLine, Menu, CreditCard, FolderOpen, FileText, FileCode, History,
 35→  Fuel, User as UserIcon, PenTool, Code, ClipboardList, ChevronDown, ChevronRight,
 36→  Archive, CheckSquare, Sparkles, Users, MessageSquare, Bell, ShoppingBag,
 37→  Settings, Construction, BarChart3, Wrench, Share2, Feather, Shield, X,
 38→  Search, Activity, BookOpen, UserCircle
 39→} from 'lucide-react';
 40→import { I18nProvider, useTranslation, LanguageSelector } from './i18n';
 41→
 42→const PLAN_LIMITS = {
 43→  free: 1,
 44→  pro: 3,
 45→  enterprise: 1000 // Illimité en pratique
 46→};
 47→
 48→const App: React.FC = () => {
 49→  return (
 50→    <I18nProvider>
 51→      <AppContent />
 52→    </I18nProvider>
 53→  );
 54→};
 55→
 56→const AppContent: React.FC = () => {
 57→  const { t, tf, locale } = useTranslation();
 58→  const [currentView, setCurrentView] = useState<'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation' | 'bot-tracking' | 'mission-orders'>('home');
 59→  const [viewHistory, setViewHistory] = useState<string[]>([]);
 60→  const [refreshKey, setRefreshKey] = useState(0); // Used to force remount of components
 61→  
 62→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
 63→  const [history, setHistory] = useState<AnalysisResult[]>([]);
 64→  
 65→  // Load history from DB on mount
 66→  useEffect(() => {
 67→    const loadedHistory = db.getAll();
 68→    setHistory(loadedHistory);
 69→  }, []);
 70→
 71→  // Bibliothèques de contenu généré
 72→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]); 
 73→  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
 74→  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
 75→  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);
 76→
 77→  const [isAnalyzing, setIsAnalyzing] = useState(false);
 78→  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
 79→  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
 80→  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
 81→  const [initialAccountTab, setInitialAccountTab] = useState<'profile' | 'subscription' | 'billing'>('profile');
 82→  
 83→  // État pour gérer l'ouverture des sections du menu (Accordion exclusif)
 84→  const [sectionsState, setSectionsState] = useState({
 85→    optimization: false,
 86→    tools: false
 87→  });
 88→  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
 89→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
 90→
 91→  // Default user is NULL to allow testing the login flow
 92→  const [user, setUser] = useState<User | null>(null);
 93→
 94→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
 95→  const monthlyProjectCount = useMemo(() => {
 96→    if (history.length === 0) return 0;
 97→
 98→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 99→    const now = new Date();
100→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
101→
102→    // 1. Identifier la date de création (première analyse) de chaque domaine
103→    const projectCreationDates = new Map<string, Date>();
104→    
105→    history.forEach(h => {
106→        let hostname;
107→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
108→        
109→        const analysisDate = new Date(h.timestamp);
110→        
111→        if (!projectCreationDates.has(hostname)) {
112→            projectCreationDates.set(hostname, analysisDate);
113→        } else {
114→            // On garde la date la plus ancienne trouvée pour ce domaine
115→            if (analysisDate < projectCreationDates.get(hostname)!) {
116→                projectCreationDates.set(hostname, analysisDate);
117→            }
118→        }
119→    });
120→
121→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
122→    let count = 0;
123→    projectCreationDates.forEach((creationDate) => {
124→        if (creationDate >= billingCycleStart) {
125→            count++;
126→        }
127→    });
128→    
129→    return count;
130→  }, [history]);
131→
132→  // Vérifier si le plan d'action est complet (toutes les recommendations ont une solution générée)
133→  const actionPlanStatus = useMemo(() => {
134→    if (history.length === 0) return { complete: false, completed: 0, total: 0 };
135→    const latest = history[history.length - 1];
136→    const total = latest.recommendations.length;
137→    const completed = latest.recommendations.filter(rec =>
138→      latest.generatedSolutions?.[rec.id]
139→    ).length;
140→    return { complete: total > 0 && completed === total, completed, total };
141→  }, [history]);
142→
143→  const navigateTo = (view: typeof currentView) => {
144→    setIsMobileMenuOpen(false);
145→    // Si on navigue vers autre chose que recharge, on reset l'ID du pack
146→    if (view !== 'recharge') {
147→        setInitialRechargePackId(null);
148→    }
149→    // Reset l'onglet du compte si on ne va pas vers le compte
150→    if (view !== 'account') {
151→        setInitialAccountTab('profile');
152→    }
153→    setViewHistory(prev => [...prev, currentView]);
154→    setCurrentView(view);
155→    setRefreshKey(prev => prev + 1); // Force remount to reset internal state of views
156→  };
157→
158→  const goBack = () => {
159→    setIsMobileMenuOpen(false);
160→    if (viewHistory.length > 0) {
161→      const newHistory = [...viewHistory];
162→      const prevView = newHistory.pop();
163→      setViewHistory(newHistory);
164→      if (prevView) {
165→        setCurrentView(prevView as any);
166→        setRefreshKey(prev => prev + 1);
167→      }
168→    } else {
169→      setCurrentView('home'); // Default fallback
170→      setRefreshKey(prev => prev + 1);
171→    }
172→  };
173→
174→  const toggleSection = (section: keyof typeof sectionsState) => {
175→    setSectionsState(prev => {
176→      const isAlreadyOpen = prev[section];
177→      return {
178→        optimization: false,
179→        tools: false,
180→        [section]: !isAlreadyOpen
181→      };
182→    });
183→  };
184→
185→  const handleHomeClick = () => {
186→    navigateTo('home');
187→    setSectionsState({
188→      optimization: false,
189→      tools: false
190→    });
191→  };
192→
193→  const handleDashboardClick = () => {
194→    navigateTo('dashboard');
195→    setSectionsState({
196→      optimization: false,
197→      tools: false
198→    });
199→  };
200→
201→  const handleRechargeClick = () => {
202→    navigateTo('recharge');
203→    setSectionsState({
204→      optimization: false,
205→      tools: false
206→    });
207→  };
208→
209→  const handleDirectRecharge = (packId: number) => {
210→    setInitialRechargePackId(packId);
211→    navigateTo('recharge');
212→  };
213→
214→  const handleAnalyze = async (url: string) => {
215→    // Vérification de la limite de projets (Quota mensuel)
216→    if (user) {
217→        const limit = PLAN_LIMITS[user.plan] || 1;
218→        let hostname = url;
219→        try { hostname = new URL(url).hostname; } catch(e) {}
220→
221→        // On vérifie si c'est un projet déjà existant dans l'historique global
222→        const isExistingProject = history.some(h => {
223→            try { return new URL(h.url).hostname === hostname; } 
224→            catch(e) { return false; }
225→        });
226→
227→        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
228→        // Les anciens projets ne comptent pas dans cette limite
229→        if (!isExistingProject && monthlyProjectCount >= limit) {
230→            // Redirection vers l'onglet Abonnement
231→            alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan supérieur pour ajouter plus de projets.`);
232→            setInitialAccountTab('subscription');
233→            navigateTo('account');
234→            return;
235→        }
236→    }
237→
238→    setIsAnalyzing(true);
239→    try {
240→      const result = await analyzeUrl(url);
241→      setAnalysisData(result);
242→      
243→      // Update history via DB service
244→      const updatedHistory = db.add(result);
245→      setHistory(updatedHistory);
246→      
247→      // Redirection vers Monitoring AEO → onglet Rapport d'Audit
248→      setResultsTab('details');
249→      navigateTo('projects');
250→      setSectionsState({
251→        optimization: false,
252→        tools: false
253→      });
254→    } catch (error) {
255→      console.error("Analysis failed", error);
256→      alert("Erreur lors de l'analyse. Veuillez réessayer.");
257→    } finally {
258→      setIsAnalyzing(false);
259→    }
260→  };
261→
262→  // Used for Admin/User private analysis view
263→  const handleViewAnalysis = (result: AnalysisResult, tab: any = 'overview') => {
264→    setAnalysisData(result);
265→    setResultsTab(tab);
266→    // Redirect to Projects (Monitoring AEO) instead of Results (Report)
267→    navigateTo('projects');
268→    setSectionsState({
269→        optimization: true,
270→        tools: false
271→    });
272→  };
273→
274→  // New handler for Public Directory View
275→  const handleViewDirectoryEntity = (result: AnalysisResult) => {
276→    setAnalysisData(result);
277→    navigateTo('directory-entity');
278→  };
279→
280→  const handleSubMenuNavigation = (tab: 'overview' | 'details' | 'archives') => {
281→    if (analysisData) {
282→      setResultsTab(tab);
283→      navigateTo('results');
284→    } else if (history.length > 0) {
285→      handleViewAnalysis(history[0], tab);
286→    } else {
287→      alert("Veuillez d'abord lancer une analyse pour accéder au plan d'actions.");
288→      navigateTo('analyze');
289→    }
290→  };
291→
292→  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
293→    const updatedHistory = db.update(index, updatedData);
294→    setHistory(updatedHistory);
295→  };
296→
297→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
298→    const timestamp = new Date().toISOString();
299→    const solutionWithMeta = { ...solution, timestamp };
300→
301→    setAnalysisData(prev => {
302→        if (!prev || prev.timestamp !== analysisId) return prev;
303→        
304→        return {
305→            ...prev,
306→            generatedSolutions: {
307→                ...(prev.generatedSolutions || {}),
308→                [recommendationId]: solutionWithMeta
309→            }
310→        };
311→    });
312→
313→    // We need to find the index in the history to update the DB
314→    setHistory(prevHistory => {
315→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
316→        if (index !== -1) {
317→            const updatedItem = {
318→                ...prevHistory[index],
319→                generatedSolutions: {
320→                    ...(prevHistory[index].generatedSolutions || {}),
321→                    [recommendationId]: solutionWithMeta
322→                }
323→            };
324→            // Persist using db service
325→            const newHistory = [...prevHistory];
326→            newHistory[index] = updatedItem;
327→            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
328→            db.update(index, updatedItem);
329→            return newHistory;
330→        }
331→        return prevHistory;
332→    });
333→  }, []); 
334→
335→  // Helpers pour ajouter du contenu aux bibliothèques
336→  const handleAddToSmcLibrary = (item: SMCContent) => setSmcLibrary(prev => [item, ...prev]);
337→  const handleAddToTruthLibrary = (item: SMCContent) => setTruthLibrary(prev => [item, ...prev]);
338→  const handleAddToSchemaLibrary = (item: SMCContent) => setSchemaLibrary(prev => [item, ...prev]);
339→  const handleAddToRobotsLibrary = (item: SMCContent) => setRobotsLibrary(prev => [item, ...prev]);
340→
341→  const handleNavigateToPublisher = (data: { topic: string, url: string, brief: string }) => {
342→    setPublisherRequestData(data);
343→    navigateTo('publisher-request');
344→  };
345→
346→  const handleNavigateToDirectory = () => {
347→    navigateTo('directory');
348→  };
349→
350→  const handleDeductCredits = (amount: number): boolean => {
351→    if (!user) {
352→        if(confirm("Vous devez être connecté pour effectuer cette action. Se connecter maintenant ?")) {
353→            navigateTo('login');
354→        }
355→        return false;
356→    }
357→    
358→    if (user.credits < amount) {
359→        // Redirection explicite vers la section GTO Gas (Recharge)
360→        alert(`Solde GTO Gas insuffisant pour générer cette solution.\n\nIl vous manque ${amount - user.credits} crédits.\n\nRedirection vers la station de recharge...`);
361→        navigateTo('recharge');
362→        return false;
363→    }
364→    
365→    setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
366→    return true;
367→  };
368→
369→  const handleRecharge = (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => {
370→    if (!user) return;
371→    
372→    setUser({ 
373→        ...user, 
374→        credits: user.credits + amount,
375→        plan: planLevel 
376→    });
377→    
378→    // Si c'est une recharge depuis la page de recharge, on ne force pas le retour, l'UX est gérée dans Recharge.tsx
379→  };
380→
381→  const handleUpgradePlan = (newPlan: 'free' | 'pro' | 'enterprise') => {
382→    if (!user) return;
383→    setUser({ ...user, plan: newPlan });
384→  };
385→
386→  const handleLogin = (loggedInUser: User) => {
387→    setUser(loggedInUser);
388→    // On réinitialise l'historique pour éviter que le bouton retour ne renvoie au login
389→    // et on force la navigation vers le dashboard
390→    setViewHistory(['home']); 
391→    setCurrentView('analyze'); // Redirection vers Nouvel Audit
392→    setRefreshKey(prev => prev + 1);
393→  };
394→
395→  const handleLogout = () => {
396→    setIsMobileMenuOpen(false);
397→    setUser(null);
398→    setCurrentView('home');
399→    setViewHistory([]);
400→    setRefreshKey(prev => prev + 1);
401→  };
402→
403→  useEffect(() => {
404→    if (!user && isMobileMenuOpen) {
405→      setIsMobileMenuOpen(false);
406→    }
407→  }, [user, isMobileMenuOpen]);
408→
409→  useEffect(() => {
410→    if (!isMobileMenuOpen) return;
411→    const previousOverflow = document.body.style.overflow;
412→    document.body.style.overflow = 'hidden';
413→    return () => {
414→      document.body.style.overflow = previousOverflow;
415→    };
416→  }, [isMobileMenuOpen]);
417→
418→  const NavItem = ({ view, label, icon: Icon, onClick, active, collapsed }: { view?: typeof currentView, label: string, icon: React.ElementType, onClick?: () => void, active?: boolean, collapsed?: boolean }) => {
419→    const handleClick = onClick ? onClick : () => view && navigateTo(view);
420→    const isActive = active !== undefined ? active : (view && currentView === view);
421→
422→    if (collapsed) {
423→      return (
424→        <button
425→          onClick={handleClick}
426→          title={label}
427→          className={`w-full flex items-center justify-center py-2.5 rounded-xl transition-all duration-200 group ${
428→            isActive
429→              ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
430→              : 'text-gray-400 hover:text-white hover:bg-white/[0.06]'
431→          }`}
432→        >
433→          <Icon size={18} className={isActive ? "text-white" : "text-gray-500 group-hover:text-gray-300"} />
434→        </button>
435→      );
436→    }
437→
438→    return (
439→      <button
440→        onClick={handleClick}
441→        className={`w-full flex items-center gap-3 px-3.5 py-2.5 rounded-xl text-[13.5px] transition-all duration-200 group font-sans ${
442→          isActive
443→            ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white font-semibold shadow-lg shadow-purple-900/30'
444→            : 'text-gray-400 hover:text-white hover:bg-white/[0.06] font-medium'
445→        }`}
446→      >
447→        <Icon size={17} className={isActive ? "text-white" : "text-gray-500 group-hover:text-gray-300"} />
448→        <span>{label}</span>
449→      </button>
450→    );
451→  };
452→
453→  const PlaceholderView = ({ title, icon: Icon }: { title: string, icon: React.ElementType }) => (
454→    <div className="flex flex-col items-center justify-center h-[80vh] text-center p-8 animate-in fade-in zoom-in duration-300">
455→      <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center mb-6 shadow-inner border border-white/10">
456→        <Icon size={48} className="text-gray-500 opacity-50" />
457→      </div>
458→      <h2 className="text-3xl font-serif font-bold text-white mb-4">{title}</h2>
459→      <p className="text-gray-400 max-w-md mb-8">
460→        {t.common.featureInDev}
461→      </p>
462→      <button
463→        onClick={() => navigateTo('dashboard')}
464→        className="px-6 py-3 bg-white/10 hover:bg-white/20 text-white rounded-xl transition-all flex items-center gap-2 font-medium"
465→      >
466→        <LayoutDashboard size={18} /> {t.common.returnToDashboard}
467→      </button>
468→    </div>
469→  );
470→
471→  return (
472→    <div className="min-h-screen flex flex-col font-sans text-gray-100 selection:bg-primary/30 bg-black">
473→      {/* Fixed Full-Width Navbar */}
474→      <nav className="fixed top-0 left-0 right-0 z-50 bg-[#0e0e18] border-b border-white/[0.06] shadow-lg shadow-black/30">
475→        <div className="px-6 h-14 flex items-center justify-between">
476→          <div className="flex items-center gap-2.5">
477→            {user && (
478→              <button
479→                type="button"
480→                onClick={() => setIsMobileMenuOpen(prev => !prev)}
481→                className="md:hidden w-9 h-9 rounded-full border border-white/[0.08] bg-white/[0.03] text-gray-300 hover:text-white hover:bg-white/[0.06] transition-colors flex items-center justify-center"
482→                aria-label={isMobileMenuOpen ? "Fermer le menu" : "Ouvrir le menu"}
483→                aria-expanded={isMobileMenuOpen}
484→                aria-controls="mobile-sidebar-menu"
485→              >
486→                {isMobileMenuOpen ? <X size={17} /> : <Menu size={17} />}
487→              </button>
488→            )}
489→            {user && (
490→              <button
491→                type="button"
492→                onClick={() => setIsSidebarCollapsed(prev => !prev)}
493→                className="hidden md:flex w-9 h-9 rounded-full border border-white/[0.08] bg-white/[0.03] text-gray-300 hover:text-white hover:bg-white/[0.06] transition-colors items-center justify-center"
494→                aria-label={isSidebarCollapsed ? "Ouvrir le menu" : "Réduire le menu"}
495→              >
496→                <Menu size={17} />
497→              </button>
498→            )}
499→            <div
500→              className="flex items-center gap-2.5 cursor-pointer"
501→              onClick={() => navigateTo('home')}
502→            >
503→            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center shadow-lg shadow-purple-900/40">
504→              <Zap size={16} className="text-white fill-white" />
505→            </div>
506→            <span className="font-sans text-lg font-bold tracking-tight hidden sm:block">
507→              <span className="text-white">CitedBy</span><span className="text-amber-400">.ai</span>
508→            </span>
509→            </div>
510→          </div>
511→
512→          <div className="flex items-center gap-5">
513→            {user ? (
514→              <div className="flex items-center gap-3">
515→                <LanguageSelector compact />
516→                {/* Bell notification */}
517→                <button
518→                  onClick={() => navigateTo('alerts')}
519→                  className="relative w-9 h-9 rounded-full bg-white/[0.04] border border-white/[0.06] flex items-center justify-center text-gray-400 hover:text-white hover:bg-white/[0.08] transition-colors"
520→                  title="Notifications"
521→                >
522→                  <Bell size={16} />
523→                  <span className="absolute -top-0.5 -right-0.5 w-3 h-3 bg-amber-500 rounded-full border-2 border-[#0e0e18]"></span>
524→                </button>
525→                {/* Credits badge */}
526→                <button
527→                  onClick={() => navigateTo('recharge')}
528→                  className="hidden md:flex items-center gap-2 px-3.5 py-1.5 rounded-full bg-amber-500/10 border border-amber-500/20 hover:bg-amber-500/20 transition-colors group"
529→                  title="Recharger GTO Gas"
530→                >
531→                  <Fuel size={14} className="text-amber-400" />
532→                  <span className="text-sm font-bold text-amber-400">{user.credits.toLocaleString()}</span>
533→                  <span className="text-xs text-amber-400/70 font-medium">Credits</span>
534→                </button>
535→                <div className="flex items-center gap-2.5">
536→                   <div
537→                     className="text-right hidden sm:block cursor-pointer"
538→                     onClick={() => navigateTo('account')}
539→                   >
540→                     <p className="text-sm font-semibold text-white leading-none hover:text-purple-400 transition-colors">{user.name}</p>
541→                     <p className="text-[10px] text-gray-500 uppercase tracking-wider mt-0.5">{user.plan === 'free' ? 'Admin' : user.plan.toUpperCase()}</p>
542→                   </div>
543→                   <button
